   813→    // Audio level meter using Web Audio API
   814→    function startAudioLevelMeter(stream) {
   815→      try {
   816→        audioContext = new (window.AudioContext || window.webkitAudioContext)();
   817→        const source = audioContext.createMediaStreamSource(stream);
   818→        audioAnalyser = audioContext.createAnalyser();
   819→        audioAnalyser.fftSize = 256;
   820→        audioAnalyser.smoothingTimeConstant = 0.8;
   821→        source.connect(audioAnalyser);
   822→
   823→        const dataArray = new Uint8Array(audioAnalyser.frequencyBinCount);
   824→
   825→        function updateLevel() {
   826→          if (!audioAnalyser) return;
   827→
   828→          audioAnalyser.getByteFrequencyData(dataArray);
   829→
   830→          // Calculate average level
   831→          let sum = 0;
   832→          for (let i = 0; i < dataArray.length; i++) {
   833→            sum += dataArray[i];
   834→          }
   835→          const avg = sum / dataArray.length;
   836→          const level = Math.min(100, (avg / 128) * 100);
   837→
   838→          // Update both mic level bars
   839→          const previewFill = document.getElementById('mic-level-fill');
   840→          const recordingFill = document.getElementById('recording-mic-level');
   841→
   842→          if (previewFill) previewFill.style.width = level + '%';
   843→          if (recordingFill) recordingFill.style.width = level + '%';
   844→
   845→          micLevelAnimationId = requestAnimationFrame(updateLevel);
   846→        }
   847→
   848→        updateLevel();
   849→      } catch (err) {
   850→        console.warn('Audio level meter not available:', err);
   851→      }
   852→    }
