          ? JSON.parse(row.analysis_data)
          : row.analysis_data
      })),
      aggregate_scores: {
        presentation: avgPresentationScore
      }
    });
  } catch (err) {
    console.error('Get analysis error:', err);
    res.status(500).json({ error: 'Failed to fetch analysis' });
  }
});

module.exports = router;

