  // Check camera access before starting
  if (!mediaStream) {
    alert('Camera and microphone are required. Please grant camera/mic permissions in your browser settings and reload the page.');
    return;
  }

  // Verify stream is still active
  const videoTracks = mediaStream.getVideoTracks();
  const audioTracks = mediaStream.getAudioTracks();
  if (videoTracks.length === 0 || videoTracks[0].readyState !== 'live') {
    alert('Camera stream lost. Please reload the page and grant camera permissions.');
    return;
  }
  if (audioTracks.length === 0 || audioTracks[0].readyState !== 'live') {
    alert('Microphone stream lost. Please reload the page and grant microphone permissions.');
    return;
  }

